            dayTimeline:[{time:'9:00',icon:'fa-book',title:'Universidade de Coimbra lecture',desc:'UC was founded in 1290 — one of the world\'s oldest universities. The hilltop campus is UNESCO-listed.'},{time:'13:00',icon:'fa-utensils',title:'Chanfana or arroz de lampreia',desc:'Traditional Portuguese cuisine at student prices. The tasca restaurants around Largo da Portagem serve excellent lunches for €7.'},{time:'15:00',icon:'fa-book',title:'Biblioteca Joanina',desc:'One of Europe\'s most spectacular baroque libraries — 300,000 books and a colony of bats that protect them at night.'},{time:'19:00',icon:'fa-music',title:'Fado Académico evening',desc:'Coimbra Fado is different from Lisbon Fado — deeper, more melancholic, traditionally performed only by male students in black cloaks.'},{time:'22:00',icon:'fa-moon',title:'Baixa nightlife',desc:'The student bar strip around Praça da República — cheap, lively, and authentic Portuguese student culture.'}],
